const prevData = $input.first().json || {};
const compact = (value) => String(value ?? '').trim();
const helperRequest =
  typeof $httpRequest === 'function'
    ? $httpRequest
    : typeof this !== 'undefined' && this?.helpers?.httpRequest
      ? this.helpers.httpRequest.bind(this.helpers)
      : null;

function parseSequence(value) {
  if (Array.isArray(value)) return value;
  if (!value) return [];
  try {
    const parsed = JSON.parse(String(value));
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

function uniqueStrings(values = []) {
  const seen = new Set();
  const out = [];
  for (const value of values) {
    const key = compact(value);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    out.push(key);
  }
  return out;
}

function extractDriveFolderId(url) {
  const source = compact(url);
  const match =
    source.match(/drive\.google\.com\/drive\/folders\/([a-zA-Z0-9_-]+)/i) ||
    source.match(/[?&]id=([a-zA-Z0-9_-]+)/i);
  return match ? match[1] : null;
}

function extractDriveFileId(url) {
  const source = compact(url);
  const match =
    source.match(/drive\.google\.com\/file\/d\/([a-zA-Z0-9_-]+)/i) ||
    source.match(/[?&]id=([a-zA-Z0-9_-]+)/i);
  return match ? match[1] : null;
}

function isDriveFolderUrl(url) {
  return /drive\.google\.com\/drive\/folders\//i.test(compact(url));
}

function isDriveFileUrl(url) {
  const source = compact(url);
  return /drive\.google\.com\/file\/d\//i.test(source) || (/drive\.google\.com/i.test(source) && /[?&]id=/.test(source));
}

function directDriveDownloadUrl(fileId) {
  return 'https://drive.google.com/uc?export=download&id=' + String(fileId);
}

async function fetchText(url) {
  if (helperRequest) {
    let response;
    try {
      response = await helperRequest({
        url,
        method: 'GET',
        headers: {
          Accept: 'text/html,application/xhtml+xml',
          'User-Agent': 'Mozilla/5.0',
        },
        json: false,
        timeout: 30000,
        ignoreHttpStatusErrors: true,
        returnFullResponse: true,
      });
    } catch (error) {
      const fallbackResponse = error?.response || error?.context?.response || null;
      if (!fallbackResponse) throw error;
      response = fallbackResponse;
    }

    const statusCode = Number(response.statusCode || response.status || 0);
    const body = response.body ?? response.data ?? '';
    const text =
      typeof body === 'string'
        ? body
        : Buffer.isBuffer(body)
          ? body.toString('utf8')
          : body instanceof Uint8Array
            ? Buffer.from(body).toString('utf8')
            : body instanceof ArrayBuffer
              ? Buffer.from(new Uint8Array(body)).toString('utf8')
              : JSON.stringify(body);

    if (statusCode < 200 || statusCode >= 300) {
      throw new Error('drive_folder_listing_http_' + statusCode);
    }

    return text;
  }

  if (typeof fetch === 'function') {
    const response = await fetch(url, {
      headers: {
        Accept: 'text/html,application/xhtml+xml',
        'User-Agent': 'Mozilla/5.0',
      },
      redirect: 'follow',
    });

    if (!response.ok) {
      throw new Error('drive_folder_listing_http_' + response.status);
    }

    return response.text();
  }

  throw new Error('drive_folder_listing_unavailable');
}

async function resolveFolderAssets(folderUrl) {
  const folderId = extractDriveFolderId(folderUrl);
  if (!folderId) {
    throw new Error('drive_folder_id_not_found');
  }

  const embedUrl = 'https://drive.google.com/embeddedfolderview?id=' + folderId + '#list';
  const html = await fetchText(embedUrl);
  const matches = Array.from(html.matchAll(/https:\/\/drive\.google\.com\/file\/d\/([a-zA-Z0-9_-]+)\/view/gi));

  return uniqueStrings(matches.map((match) => directDriveDownloadUrl(match[1]))).map((downloadUrl) => ({
    source_url: folderUrl,
    download_url: downloadUrl,
  }));
}

async function resolveSequenceAssets(item) {
  const rawUrls = uniqueStrings([
    ...(Array.isArray(item.media_urls) ? item.media_urls : []),
    item.media_url,
  ]);

  const assets = [];

  for (const url of rawUrls) {
    if (isDriveFolderUrl(url)) {
      const resolved = await resolveFolderAssets(url);
      assets.push(...resolved);
      continue;
    }

    if (isDriveFileUrl(url)) {
      const fileId = extractDriveFileId(url);
      if (fileId) {
        assets.push({
          source_url: url,
          download_url: directDriveDownloadUrl(fileId),
        });
        continue;
      }
    }

    assets.push({
      source_url: url,
      download_url: url,
    });
  }

  return uniqueStrings(assets.map((asset) => asset.download_url)).map((downloadUrl) => ({
    download_url: downloadUrl,
    source_url: assets.find((asset) => asset.download_url === downloadUrl)?.source_url || downloadUrl,
  }));
}

function blockWaitMs(photoCount) {
  const count = Number(photoCount || 0);
  return Math.max(15000, 15000 + Math.max(0, count) * 6000);
}

function createTextItem(content, extra = {}) {
  const message = compact(content);
  if (!message) return null;

  return {
    json: {
      ...prevData,
      outbound_item_type: 'text',
      content: message,
      private: extra.private === true,
      property_title: extra.property_title || null,
      source_url: extra.source_url || null,
      download_url: extra.download_url || null,
      send_order: extra.send_order || 0,
      media_relay_base_url: compact(prevData.media_relay_base_url || ""),
      property_group_id: extra.property_group_id || null,
      wait_after_block_ms: extra.wait_after_block_ms || null,
    },
  };
}

const rawSequence = parseSequence(prevData.outbound_sequence_json || prevData.outbound_sequence);
const fallbackMessage = compact(prevData.outbound_message || prevData.final_whatsapp_text);
const queue = rawSequence.length
  ? rawSequence
  : fallbackMessage
    ? [{ type: 'text', content: fallbackMessage, private: prevData.private === true }]
    : [];

const outboundItems = [];
let sendOrder = 1;

for (const rawItem of queue) {
  const item = rawItem && typeof rawItem === 'object' ? rawItem : null;
  if (!item) continue;

  const itemType = compact(item.type || '');
  const isMediaItem = itemType === 'media_group' || (compact(item.media_url) && itemType !== 'text');

  if (!isMediaItem) {
    const textItem = createTextItem(item.content, {
      private: item.private === true || prevData.private === true,
      send_order: sendOrder,
    });
    if (textItem) {
      outboundItems.push(textItem);
      sendOrder += 1;
    }
    continue;
  }

  const rawUrls = uniqueStrings([
    ...(Array.isArray(item.media_urls) ? item.media_urls : []),
    item.media_url,
  ]);

  let assets = [];
  try {
    assets = await resolveSequenceAssets(item);
  } catch {
    assets = [];
  }

  if (!assets.length) {
    const fallbackText = [compact(item.content), ...rawUrls].filter(Boolean).join('\n');
    const textItem = createTextItem(fallbackText, {
      private: item.private === true || prevData.private === true,
      property_title: item.property_title || null,
      source_url: rawUrls[0] || null,
      send_order: sendOrder,
    });
    if (textItem) {
      outboundItems.push(textItem);
      sendOrder += 1;
    }
    continue;
  }

  const propertyGroupId = compact(item.property_group_id || item.property_id || item.property_title || 'media-block-' + sendOrder);
  const waitAfterBlockMs = blockWaitMs(assets.length);

  for (let index = 0; index < assets.length; index += 1) {
    const asset = assets[index];
    const caption = index === 0 ? compact(item.content) : '';
    const isLastAsset = index === assets.length - 1;

    outboundItems.push({
      json: {
        ...prevData,
        outbound_item_type: 'media_asset',
        property_title: item.property_title || null,
        private: item.private === true || prevData.private === true,
        caption,
        send_caption: Boolean(caption),
        asset_index: index,
        source_url: asset.source_url || rawUrls[0] || null,
        download_url: asset.download_url,
        send_order: sendOrder,
        media_relay_base_url: compact(prevData.media_relay_base_url || ""),
        property_group_id: propertyGroupId,
        property_group_photo_count: assets.length,
        wait_after_block_ms: isLastAsset ? waitAfterBlockMs : null,
      },
    });
    sendOrder += 1;
  }
}

if (!outboundItems.length) {
  return [
    {
      json: {
        ...prevData,
        outbound_item_type: 'noop',
        send_order: 0,
        media_relay_base_url: compact(prevData.media_relay_base_url || ""),
      },
    },
  ];
}

return outboundItems;

const items = $input.all();
const current = items[0]?.json || {};
const hasPreUpload = Boolean(current.whatsapp_media_id);
const waitMs = Number(current.wait_after_block_ms || 0);

let delay;
if (hasPreUpload) {
  // Pre-uploaded media: minimal delay, just respect rate limits
  delay = waitMs > 0 ? Math.min(waitMs, 1500) : 500;
} else {
  // Chatwoot path: keep original longer waits
  delay = Number.isFinite(waitMs) && waitMs > 0 ? waitMs : 350;
}

await new Promise((resolve) => setTimeout(resolve, delay));
return items;

