    ok: json.result_ok !== false,
    type: compact(json.result_type),
    filename: compact(json.result_filename) || null,
    property_title: compact(json.result_property_title) || null,
    source_url: compact(json.result_source_url) || null,
    error: compact(json.result_error) || null,
    fallback_sent: json.result_fallback_sent === true,
    content: compact(json.result_content) || null,
  }));

return [
  {
    json: {
      ok: results.every((entry) => entry.ok !== false),
      chatwoot_id: compact(first.chatwoot_id) || null,
      sent_count: results.length,
      results,
    },
  },
];

const items = $input.all();
const compact = (v) => String(v ?? '').trim();

// Collect unique download_urls from media items
const mediaItems = items.filter(item => item.json.outbound_item_type === 'media_asset' && compact(item.json.download_url));
const uniqueUrls = [...new Set(mediaItems.map(item => compact(item.json.download_url)))];

if (!uniqueUrls.length) {
  // No media to pre-upload, pass through all items unchanged
  return items;
}

// Build assets array for pre-upload
const assets = uniqueUrls.map(url => ({ download_url: url }));

// Call pre-upload endpoint
const mediaRelayBase = compact(items[0]?.json?.media_relay_base_url || '');
const preUploadUrl = (mediaRelayBase || 'http://localhost:3101') + '/api/whatsapp/pre-upload';

let mediaIdMap = new Map();
try {
  const response = await this.helpers.httpRequest({
    url: preUploadUrl,
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ assets }),
    timeout: 120000,
    json: true,
  });

  if (response?.ok && Array.isArray(response.results)) {
    for (const result of response.results) {
      if (result.ok && result.media_id) {
        mediaIdMap.set(compact(result.download_url), {
          media_id: result.media_id,
          mime_type: result.mime_type || 'image/jpeg',
        });
      }
    }
  }
} catch (err) {
  // Pre-upload failed, items will fall back to Chatwoot path
  console.log('[pre-upload] Failed:', err.message || err);
}

const uploaded = mediaIdMap.size;
const total = uniqueUrls.length;
console.log('[pre-upload] ' + uploaded + '/' + total + ' media assets pre-uploaded to WhatsApp');

// Attach media_ids to items
return items.map(item => {
  const url = compact(item.json.download_url);
  const preUploaded = url ? mediaIdMap.get(url) : null;
  return {
    json: {
      ...item.json,
      whatsapp_media_id: preUploaded?.media_id || null,
      whatsapp_media_mime: preUploaded?.mime_type || null,
    },
  };
});

